class Person:
    def initialize(self, name, age, hobby):
        self.name = name
        self.age = age
        self.hobby = hobby
    def hobbyprint(self):
        print(self.name+'씨의 취미는 '+self.hobby+'입니다.')
    def ageplus(self):
        print(self.name+'씨는 10년 뒤 '+str(self.age+10)+'세가 됩니다.')

p1 = Person()
