p1.ageplus()

class Door:
    def initialize(self):
        self.상태 = '열림'
    def 현재상태출력(self):
        if self.상태 == '열림':
            print('문이 열려있습니다')
        else:
            print('문이 닫혀있습니다')
    def 상호작용(self):
        if self.상태 == '열림':
            self.상태 = '닫힘'
            print('문이 닫혔습니다')
        else:
            self.상태 = '열림'
            print('문이 열렸습니다')

